import React from "react";

const JournalCard = ({ id, title, date, entry, analyzed, onEdit, onDelete, analysis }) => {
  const previewLines = entry.split("\n").slice(0, 2).join("\n");

  return (
    <div className="journal-card">
      <h3 className="card-title">{title || "Untitled"}</h3>
      <p className="card-date">{date}</p>
      <pre className="card-preview">{previewLines}</pre>
      <div>
        Status:{" "}
        <span style={{ color: analyzed ? "green" : "red" }}>
          {analyzed ? "Analyzed" : "Not Analyzed"}
        </span>
      </div>
      {analyzed && analysis && (
        <div style={{ fontStyle: "italic", marginTop: 6, fontSize: 12 }}>{analysis}</div>
      )}
      <div style={{ marginTop: 10 }}>
        <button onClick={() => onEdit(id)} style={{ marginRight: 10 }}>
          Edit
        </button>
        <button onClick={() => onDelete(id)}>Delete</button>
      </div>
      <style>{`
        .journal-card {
          background-color: var(--secondary-color);
          color: var(--text);
          padding: 1rem;
          border-radius: 8px;
          width: 100%;
          max-width: 200px;
          box-shadow: 2px 2px 5px rgba(0,0,0,0.1);
        }

        .card-title {
          margin: 0 0 0.3rem;
          font-size: 1.3rem;
        }

        .card-date {
          font-size: 0.95rem;
          color: var(--text);
          opacity: 0.8;
          margin-bottom: 0.5rem;
        }

        .card-preview {
          white-space: pre-wrap;
          font-size: 1rem;
          height:300px;
          font-family: 'Cedarville Cursive', cursive;
        }
      `}</style>
    </div>
  );
};

export default JournalCard;
